import AppKit
import Sparkle
import SwiftUI

@MainActor
final class AppDelegate: NSObject, NSApplicationDelegate {
    let lifecycle = AppLifecycleController()
    private let loginItemController = LoginItemController()
    private let panelController = FloatingInstallPanelController()
    private let updaterController = SPUStandardUpdaterController(
        startingUpdater: true,
        updaterDelegate: nil,
        userDriverDelegate: nil
    )
    private var aboutWindowController: NSWindowController?
    private var debugMenuShortcutMonitor: Any?
    var toggleDebugMenu: (() -> Void)?

    func applicationDidFinishLaunching(_ notification: Notification) {
        NSWindow.allowsAutomaticWindowTabbing = false
        lifecycle.applicationDidFinishLaunching()
        installDebugMenuShortcutMonitor()
    }

    func applicationWillTerminate(_ notification: Notification) {
        if let debugMenuShortcutMonitor {
            NSEvent.removeMonitor(debugMenuShortcutMonitor)
        }
    }

    @discardableResult
    func configureLaunchAtLogin(_ isEnabled: Bool, showsAlert: Bool = false) -> Bool {
        do {
            try loginItemController.configureLaunchAtLogin(isEnabled)
            return true
        } catch {
            NSLog("Failed to update launch at login: \(error.localizedDescription)")
            if showsAlert {
                showLaunchAtLoginError(error)
            }
            return false
        }
    }

    private func showLaunchAtLoginError(_ error: Error) {
        let alert = NSAlert()
        alert.alertStyle = .warning
        alert.messageText = "Could Not Update Launch at Login"
        alert.informativeText = error.localizedDescription
        alert.addButton(withTitle: "OK")
        alert.runModal()
    }

    func applicationShouldHandleReopen(_ sender: NSApplication, hasVisibleWindows flag: Bool) -> Bool {
        lifecycle.applicationShouldHandleReopen(hasVisibleWindows: flag)
    }

    func applicationShouldTerminateAfterLastWindowClosed(_ sender: NSApplication) -> Bool {
        false
    }

    @MainActor
    func bind(to store: InstallStore) {
        panelController.bind(to: store)
    }

    @MainActor
    func setNotificationPosition(_ position: NotificationPosition) {
        panelController.setNotificationPosition(position)
    }

    var canCheckForUpdates: Bool {
        updaterController.updater.canCheckForUpdates
    }

    var automaticallyChecksForUpdates: Bool {
        get {
            updaterController.updater.automaticallyChecksForUpdates
        }
        set {
            updaterController.updater.automaticallyChecksForUpdates = newValue
        }
    }

    @MainActor
    func checkForUpdates() {
        updaterController.checkForUpdates(nil)
    }

    @MainActor
    func showAboutWindow() {
        if let window = aboutWindowController?.window {
            window.makeKeyAndOrderFront(nil)
            NSApp.activate(ignoringOtherApps: true)
            return
        }

        let hostingController = NSHostingController(rootView: AboutView())
        let window = NSWindow(contentViewController: hostingController)
        window.title = "About Poppy"
        window.styleMask = [.titled, .closable]
        window.titlebarAppearsTransparent = true
        window.titleVisibility = .hidden
        window.isReleasedWhenClosed = false
        window.center()

        let controller = NSWindowController(window: window)
        aboutWindowController = controller
        controller.showWindow(nil)
        NSApp.activate(ignoringOtherApps: true)
    }

    private func installDebugMenuShortcutMonitor() {
        debugMenuShortcutMonitor = NSEvent.addLocalMonitorForEvents(matching: .keyDown) { [weak self] event in
            guard event.charactersIgnoringModifiers == "." else {
                return event
            }

            let requiredModifiers: NSEvent.ModifierFlags = [.command, .shift]
            let activeModifiers = event.modifierFlags.intersection(.deviceIndependentFlagsMask)
            guard activeModifiers == requiredModifiers else {
                return event
            }

            self?.toggleDebugMenu?()
            return nil
        }
    }
}

